import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  // ✅ state للنص المتغير
  const [index, setIndex] = useState(0);

  // ✅ state للصورة المكبرة
  const [selectedImage, setSelectedImage] = useState(null);

  // ✅ تغيير النص كل 2 ثواني
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  // ✅ بيانات الصور الثلاث (أفقية)
  const galleryImages = [
    {
      id: 1,
      title: "رمز QR",
      description: "مسح سريع وطلب مباشر",
      imageUrl: "https://placehold.co/600x400/2c3e50/ffffff?text=📱+QR+Code",
      modalContent: {
        title: "رمز QR - بدء الطلب",
        details: "يقوم الزبون بمسح رمز QR الموجود على الطاولة، ليتم فتح قائمة الطعام الرقمية مباشرة على هاتفه ويمكنه إرسال الطلب للمطبخ بضغطة زر."
      }
    },
    {
      id: 2,
      title: "العامل والطلبات",
      description: "إدارة فعالة وسريعة",
      imageUrl: "https://placehold.co/600x400/34495e/ffffff?text=👨‍🍳+Waiter",
      modalContent: {
        title: "العامل والطلبات",
        details: "يستقبل العامل الطلبات مباشرة على جهازه اللوحي، مع تفاصيل كل طلب: اسم الطبق، الكمية، الملاحظات الخاصة، ومكان الطاولة."
      }
    },
    {
      id: 3,
      title: "الفاتورة الذكية",
      description: "حساب آلي دقيق",
      imageUrl: "https://placehold.co/600x400/16a085/ffffff?text=🧾+Invoice",
      modalContent: {
        title: "الفاتورة الذكية",
        details: "يقوم النظام تلقائياً بحساب إجمالي الطلبات مع الضريبة، ويظهر تفاصيل كل صنف وسعره، مع خيارات دفع متعددة."
      }
    }
  ];

  // ✅ دالة فتح الصورة المكبرة
  const openModal = (image) => {
    setSelectedImage(image);
    document.body.style.overflow = "hidden"; // منع التمرير خلف المودال
  };

  // ✅ دالة إغلاق المودال
  const closeModal = () => {
    setSelectedImage(null);
    document.body.style.overflow = "auto";
  };

  return (
    <>
      <Navbar transparent />
      <main>
        {/* قسم الصور الثلاث أفقيًا بدلاً من الخلفية الواحدة */}
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen bg-gradient-to-br from-gray-900 to-gray-700">
          {/* شبكة الصور الثلاث أفقياً */}
          <div className="container relative mx-auto px-4">
            <div className="text-center mb-12">
              {/* النص المتحرك يبقى */}
              <h1
                key={texts[index]}
                className="text-white font-semibold text-5xl md:text-6xl transition-all duration-500 mb-4"
              >
                {texts[index]}
              </h1>
              <p className="text-lg text-gray-200">
                مرحباً بك في نظام إدارة المطاعم الذكي
              </p>
              <p className="text-md text-gray-300 mt-2">
                اضغط على أي صورة لمعرفة المزيد عن المهمة
              </p>
            </div>

            {/* الصور الثلاث جنباً إلى جنب (أفقياً) */}
            <div className="flex flex-wrap justify-center gap-6 md:gap-8">
              {galleryImages.map((image) => (
                <div
                  key={image.id}
                  onClick={() => openModal(image)}
                  className="group relative w-full sm:w-80 md:w-72 lg:w-80 cursor-pointer transform transition-all duration-300 hover:-translate-y-2"
                >
                  <div className="relative rounded-xl overflow-hidden shadow-xl hover:shadow-2xl transition-shadow">
                    <img
                      src={image.imageUrl}
                      alt={image.title}
                      className="w-full h-64 object-cover transition-transform duration-500 group-hover:scale-110"
                    />
                    {/* تراكب شفاف مع النص عند التمرير */}
                    <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-60 transition-all duration-300 flex items-center justify-center">
                      <div className="text-center text-white opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-y-4 group-hover:translate-y-0">
                        <h3 className="text-xl font-bold mb-2">{image.title}</h3>
                        <p className="text-sm px-4">{image.description}</p>
                        <span className="inline-block mt-3 text-sm bg-white text-gray-800 px-3 py-1 rounded-full">
                          اضغط للمزيد
                        </span>
                      </div>
                    </div>
                  </div>
                  <div className="text-center mt-3">
                    <p className="text-white font-medium">{image.title}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* باقي محتوى الصفحة (يمكنك إضافة أقسام أخرى هنا) */}

      </main>
      <Footer />

      {/* مودال عرض الصورة المكبرة مع المحتوى */}
      {selectedImage && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-90 backdrop-blur-sm transition-all duration-300"
          onClick={closeModal}
        >
          <div
            className="relative max-w-4xl w-full bg-white rounded-2xl overflow-hidden shadow-2xl transform transition-all duration-300 scale-100"
            onClick={(e) => e.stopPropagation()}
          >
            {/* زر الإغلاق */}
            <button
              onClick={closeModal}
              className="absolute top-4 right-4 z-10 bg-black bg-opacity-50 hover:bg-opacity-70 text-white w-10 h-10 rounded-full flex items-center justify-center transition-colors"
            >
              ✕
            </button>

            <div className="flex flex-col md:flex-row">
              {/* الصورة المكبرة */}
              <div className="md:w-1/2 bg-gray-100">
                <img
                  src={selectedImage.imageUrl}
                  alt={selectedImage.title}
                  className="w-full h-64 md:h-full object-cover"
                />
              </div>

              {/* المحتوى التوضيحي */}
              <div className="md:w-1/2 p-6 md:p-8">
                <h2 className="text-2xl md:text-3xl font-bold text-gray-800 mb-4">
                  {selectedImage.modalContent.title}
                </h2>
                <p className="text-gray-600 leading-relaxed mb-6">
                  {selectedImage.modalContent.details}
                </p>
                <div className="border-t pt-4">
                  <p className="text-sm text-gray-500">
                    ✨ هذا جزء من مهام التطبيق الرئيسية
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
